class Logger:
    LEVELS = {'DEBUG': 1, 'INFO': 2, 'WARN': 3, 'ERROR': 4}

    def __init__(self, threshold='INFO'):
        self.threshold = self.LEVELS[threshold]

    def log(self, level_name, msg):
        level_val = self.LEVELS[level_name]
        if level_val >= self.threshold:
            print(f"[{level_name}] {msg}")

    def debug(self, msg): self.log('DEBUG', msg)
    def info(self, msg): self.log('INFO', msg)
    def error(self, msg): self.log('ERROR', msg)

log = Logger('INFO')
log.debug("Connecting to DB...") # Shouldn't print
log.info("Server started on port 80")
log.error("DB Connection failed!")
